--
-- Table structure for table `kontrak`
--

DROP TABLE IF EXISTS `kontrak`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `kontrak` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `parent_contract_id` int unsigned DEFAULT NULL COMMENT 'Parent contract ID for renewals',
  `is_renewal` tinyint(1) DEFAULT '0' COMMENT 'Is this a renewal contract',
  `renewal_generation` int unsigned DEFAULT '0' COMMENT 'Renewal generation number',
  `renewal_initiated_at` datetime DEFAULT NULL,
  `renewal_initiated_by` int unsigned DEFAULT NULL,
  `renewal_completed_at` datetime DEFAULT NULL,
  `customer_location_id` int DEFAULT NULL,
  `no_kontrak` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `rental_type` enum('CONTRACT','PO_ONLY','DAILY_SPOT') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'CONTRACT' COMMENT 'Rental classification: CONTRACT=formal contract with/without PO, PO_ONLY=PO-based no formal contract, DAILY_SPOT=daily rental no contract/PO',
  `customer_po_number` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Customer Purchase Order number (external PO from customer, NOT internal PO marketing)',
  `nilai_total` decimal(15,2) DEFAULT NULL COMMENT 'Nilai total kontrak dalam rupiah',
  `total_units` int unsigned NOT NULL DEFAULT '0' COMMENT 'Total unit yang terkait dengan kontrak ini',
  `jenis_sewa` enum('BULANAN','HARIAN') COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Billing period: BULANAN=monthly rate, HARIAN=daily rate',
  `billing_method` enum('CYCLE','PRORATE','MONTHLY_FIXED') COLLATE utf8mb4_unicode_ci DEFAULT 'CYCLE' COMMENT 'Invoice calculation method: CYCLE=30-day rolling, PRORATE=month-end billing, MONTHLY_FIXED=fixed date',
  `tanggal_mulai` date NOT NULL,
  `tanggal_berakhir` date NOT NULL,
  `status` enum('ACTIVE','EXPIRED','PENDING','CANCELLED') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'PENDING' COMMENT 'Contract status: ACTIVE=running, EXPIRED=ended naturally, PENDING=awaiting activation, CANCELLED=terminated early',
  `dibuat_oleh` int unsigned DEFAULT NULL,
  `dibuat_pada` datetime DEFAULT CURRENT_TIMESTAMP,
  `diperbarui_pada` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `billing_notes` text COLLATE utf8mb4_unicode_ci COMMENT 'Special billing instructions',
  `billing_start_date` date DEFAULT NULL COMMENT 'Custom billing cycle start date',
  `fast_track` tinyint(1) DEFAULT '0',
  `spot_rental_number` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `estimated_duration_days` int DEFAULT NULL,
  `actual_return_date` date DEFAULT NULL,
  `requires_po_approval` tinyint(1) DEFAULT '0',
  PRIMARY KEY (`id`),
  KEY `idx_kontrak_customer_location` (`customer_location_id`),
  KEY `idx_kontrak_status` (`status`),
  KEY `idx_kontrak_status_date` (`status`,`dibuat_pada`),
  KEY `idx_kontrak_nilai` (`nilai_total`),
  KEY `idx_rental_type` (`rental_type`),
  KEY `idx_customer_po` (`customer_po_number`),
  KEY `idx_dates` (`tanggal_mulai`,`tanggal_berakhir`),
  KEY `idx_jenis_sewa` (`jenis_sewa`),
  KEY `idx_billing_method` (`billing_method`),
  KEY `idx_parent_contract` (`parent_contract_id`),
  KEY `idx_is_renewal` (`is_renewal`),
  KEY `idx_renewal_generation` (`renewal_generation`),
  KEY `idx_kontrak_fast_track` (`fast_track`,`status`),
  KEY `idx_kontrak_spot_rental` (`spot_rental_number`),
  CONSTRAINT `fk_kontrak_parent` FOREIGN KEY (`parent_contract_id`) REFERENCES `kontrak` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=364 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

